package com.museumheist.game.world;
import android.graphics.*;import com.museumheist.game.entity.*;import java.util.*;
public class Level {private final String title,objective;private final float worldWidth,worldHeight,startX,startY;private final RectF bounds,exit;private final List<RectF> treasures=new ArrayList<>();private final List<Wall>walls;private final List<Guard>guards;private final List<Laser>lasers;private final List<Door>doors;private final List<KeyItem>keys;private final List<SecurityCamera>cameras;private final List<PointF>spawnPoints;
 public Level(String title,String objective,float width,float height,RectF bounds,List<RectF>treasures,RectF exit,float sx,float sy,List<Wall>walls,List<Guard>guards,List<Laser>lasers,List<Door>doors,List<KeyItem>keys,List<SecurityCamera>cameras,List<PointF>spawns){this.title=title;this.objective=objective;worldWidth=width;worldHeight=height;this.bounds=new RectF(bounds);for(RectF r:treasures)this.treasures.add(new RectF(r));this.exit=new RectF(exit);startX=sx;startY=sy;this.walls=new ArrayList<>(walls);this.guards=new ArrayList<>(guards);this.lasers=new ArrayList<>(lasers);this.doors=new ArrayList<>(doors);this.keys=new ArrayList<>(keys);this.cameras=new ArrayList<>(cameras);spawnPoints=new ArrayList<>();for(PointF p:spawns)spawnPoints.add(new PointF(p.x,p.y));}
 public String getTitle(){return title;}public String getObjective(){return objective;}public float getWorldWidth(){return worldWidth;}public float getWorldHeight(){return worldHeight;}public RectF getBounds(){return bounds;}public RectF getExit(){return exit;}public float getPlayerStartX(){return startX;}public float getPlayerStartY(){return startY;}public List<RectF> getTreasures(){return Collections.unmodifiableList(treasures);}public int getTreasureCount(){return treasures.size();}public List<Wall> getWalls(){return Collections.unmodifiableList(walls);}public List<Guard> getGuards(){return Collections.unmodifiableList(guards);}public List<Laser> getLasers(){return Collections.unmodifiableList(lasers);}public List<Door> getDoors(){return Collections.unmodifiableList(doors);}public List<KeyItem> getKeyItems(){return Collections.unmodifiableList(keys);}public List<SecurityCamera> getCameras(){return Collections.unmodifiableList(cameras);}public List<PointF> getPowerUpSpawnPoints(){return Collections.unmodifiableList(spawnPoints);}public void resetDynamicObjects(){for(Guard g:guards)g.reset();for(Door d:doors)d.reset();for(KeyItem k:keys)k.reset();for(SecurityCamera c:cameras)c.reset();}
}
